impl ProgramState {
    pub fn odd_record(&self) -> bool { format!("{}", self.sub).trim() == "1" }
    pub fn null_key(&self) -> bool { format!("{}", self.sub).trim() == "4" }
}

/// OPEN INPUT TSPFILE
fn tspfile_open_input(state: &mut ProgramState) {
    let path = std::env::var("TSPFILE").unwrap_or("tspfile.dat".to_string());
    match CobolFile::open_input(&path) {
        Ok(handle) => { state._fh_tspfile = handle; state._fs_tspfile = FileStatus::Success; }
        Err(_) => { state._fs_tspfile = FileStatus::Error("35".to_string()); }
    }
    state.cust_stat = format!("{}", state._fs_tspfile).cobol_into();
}

/// OPEN OUTPUT TSPFILE
fn tspfile_open_output(state: &mut ProgramState) {
    let path = std::env::var("TSPFILE").unwrap_or("tspfile.dat".to_string());
    match CobolFile::open_output(&path) {
        Ok(handle) => { state._fh_tspfile = handle; state._fs_tspfile = FileStatus::Success; }
        Err(_) => { state._fs_tspfile = FileStatus::Error("35".to_string()); }
    }
    state.cust_stat = format!("{}", state._fs_tspfile).cobol_into();
}

